import React from "react";

function Aleart(props) {
  return (
    <>
      props.aleart&&<div className="alert alert-primary" role="alert">
        <strong>{props.aleart.type}:</strong> {props.aleart.msg}
      </div>
    </>
  );
}

export default Aleart;
